func:
const v = msg.payload;
if (typeof v === 'number' && Math.abs(v - 2.718281828) < 1e-6) {
  node.warn('[VALIDATE] C1 client READ: PASS');
} else {
  node.warn('[VALIDATE] C1 client READ: FAIL - got ' + JSON.stringify(v));
}
return msg;

const v = msg.payload;
if (typeof v === 'number' && Math.abs(v - 42.5) < 1e-6) {
  node.warn('[VALIDATE] C2 client WRITE+READBACK: PASS');
} else {
  node.warn('[VALIDATE] C2 client WRITE+READBACK: FAIL - readback ' + JSON.stringify(v));
}
return msg;

// First msg is the 'Subscribed' confirmation (payload string).
// Value-change msgs carry operation==='subscribe' and a numeric payload.
const ctx = context;
if (ctx.get('done')) { return null; }
if (msg.operation === 'subscribe' && typeof msg.payload === 'number') {
  ctx.set('done', true);
  node.warn('[VALIDATE] C3 client SUBSCRIBE: PASS (value=' + msg.payload + ')');
}
return msg;

const arr = msg.payload;
const names = Array.isArray(arr) ? arr.map(r => r.browseName) : [];
const want = ['Scalar','Dynamic','Methods'];
if (Array.isArray(arr) && want.every(w => names.includes(w))) {
  node.warn('[VALIDATE] C4 client BROWSE: PASS (' + names.join(',') + ')');
} else {
  node.warn('[VALIDATE] C4 client BROWSE: FAIL - got ' + JSON.stringify(names));
}
return msg;

const out = Array.isArray(msg.payload) ? msg.payload : [];
if (out.length >= 1 && Math.abs(Number(out[0]) - 7) < 1e-6) {
  node.warn('[VALIDATE] C5 client METHOD: PASS (result=' + out[0] + ')');
} else {
  node.warn('[VALIDATE] C5 client METHOD: FAIL - got ' + JSON.stringify(msg.payload));
}
return msg;

const eps = msg.payload;
if (Array.isArray(eps) && eps.length >= 1) {
  node.warn('[VALIDATE] C6 client GETENDPOINTS: PASS (' + eps.length + ' endpoints)');
} else {
  node.warn('[VALIDATE] C6 client GETENDPOINTS: FAIL - got ' + JSON.stringify(eps).slice(0,80));
}
return msg;

const r = msg.payload;
function val(x){ return x && (x.value !== undefined ? x.value : (x.payload !== undefined ? x.payload : x)); }
if (Array.isArray(r) && r.length === 2) {
  const d = val(r[0]); const i = val(r[1]);
  if (Math.abs(Number(d) - 2.718281828) < 1e-6 && Number(i) === -100000) {
    node.warn('[VALIDATE] C7 client READMULTIPLE: PASS (D=' + d + ', I=' + i + ')');
  } else {
    node.warn('[VALIDATE] C7 client READMULTIPLE: FAIL - values ' + JSON.stringify([d,i]));
  }
} else {
  node.warn('[VALIDATE] C7 client READMULTIPLE: FAIL - shape ' + JSON.stringify(r).slice(0,120));
}
return msg;

const r = msg.payload;
function val(x){ return x && (x.value !== undefined ? x.value : x); }
if (Array.isArray(r) && r.length === 2) {
  const d = val(r[0]); const i = val(r[1]);
  if (Math.abs(Number(d) - 2.718281828) < 1e-6 && Number(i) === -100000) {
    node.warn('[VALIDATE] I1 item COLLECTOR: PASS (2 items: D=' + d + ', I=' + i + ')');
  } else {
    node.warn('[VALIDATE] I1 item COLLECTOR: FAIL - values ' + JSON.stringify([d,i]));
  }
} else {
  node.warn('[VALIDATE] I1 item COLLECTOR: FAIL - shape ' + JSON.stringify(r).slice(0,120));
}
return msg;

const arr = msg.payload;
const names = Array.isArray(arr) ? arr.map(r => r.browseName) : [];
if (Array.isArray(arr) && arr.length >= 1 && names.includes('Scalar')) {
  node.warn('[VALIDATE] B1 opcua-browser: PASS (' + names.join(',') + ')');
} else {
  node.warn('[VALIDATE] B1 opcua-browser: FAIL - got ' + JSON.stringify(names));
}
return msg;

// browse-client read returns msg.payload = array of read results for selectedItems
const r = msg.payload;
function val(x){ return x && (x.value !== undefined ? x.value : x); }
if (Array.isArray(r) && r.length >= 1 && Math.abs(Number(val(r[0])) - 2.718281828) < 1e-6) {
  node.warn('[VALIDATE] BC1 browse-client: PASS (read selected item, value=' + val(r[0]) + ')');
} else {
  node.warn('[VALIDATE] BC1 browse-client: FAIL - got ' + JSON.stringify(r).slice(0,120));
}
return msg;

const out = Array.isArray(msg.payload) ? msg.payload : [];
if (out.length >= 1 && Math.abs(Number(out[0]) - 42) < 1e-6) {
  node.warn('[VALIDATE] M1 opcua-method: PASS (result=' + out[0] + ')');
} else {
  node.warn('[VALIDATE] M1 opcua-method: FAIL - got ' + JSON.stringify(msg.payload));
}
return msg;

// The subscribe path returns a confirmation msg.payload string. The test
// server raises no events, so we assert the subscription was established.
if (msg.operation === 'event') {
  node.warn('[VALIDATE] E1 event: PASS (event received: ' + JSON.stringify(msg.payload).slice(0,80) + ')');
} else if (typeof msg.payload === 'string' && /subscription active/i.test(msg.payload)) {
  node.warn('[VALIDATE] E1 event: PASS (subscribed without error; server raises no events to assert)');
} else {
  node.warn('[VALIDATE] E1 event: FAIL - unexpected ' + JSON.stringify(msg.payload).slice(0,100));
}
return msg;

const v = msg.payload;
if (typeof v === 'number' && Math.abs(v - 42) < 1e-6) {
  node.warn('[VALIDATE] S1 server EMBEDDED: PASS (read 42 from embedded server)');
} else {
  node.warn('[VALIDATE] S1 server EMBEDDED: FAIL - readback ' + JSON.stringify(v));
}
return msg;

const v = msg.payload;
if (typeof v === 'number' && Math.abs(v - 2.718281828) < 1e-6) {
  node.warn('[VALIDATE] AUTH1 endpoint USER/PASS: PASS (authenticated read as admin)');
} else {
  node.warn('[VALIDATE] AUTH1 endpoint USER/PASS: FAIL - got ' + JSON.stringify(v));
}
return msg;

const p = msg.payload || {};
const errs = [];
if (Math.abs(p.D - 3.14159) > 1e-9) errs.push("D=" + p.D);
if (p.S !== "hello-t1") errs.push("S=" + p.S);
if (p.I !== -12345) errs.push("I=" + p.I);
if (p.B !== true) errs.push("B=" + p.B);
if (Math.abs(p.F - 1.5) > 1e-3) errs.push("F=" + p.F);
if (p.U !== 60000) errs.push("U=" + p.U);
if (msg.encoding !== "uadp") errs.push("encoding=" + msg.encoding);
if (msg.transport !== "udp") errs.push("transport=" + msg.transport);
if (msg.publisherId === undefined) errs.push("no publisherId");
if (msg.writerGroupId !== 1) errs.push("wgId=" + msg.writerGroupId);
if (msg.dataSetWriterId !== 1) errs.push("dswId=" + msg.dataSetWriterId);
if (msg.sequenceNumber === undefined) errs.push("no seq");
node.warn(errs.length ? "[VALIDATE] T1 udp-uadp-scalars: FAIL - " + errs.join(", ")
                      : "[VALIDATE] T1 udp-uadp-scalars: PASS");
return msg;

const p = msg.payload || {};
const errs = [];
if (Math.abs(p.Temp - 42.25) > 1e-9) errs.push("Temp=" + p.Temp);
if (p.Tag !== "mqtt-uadp-t2") errs.push("Tag=" + p.Tag);
if (msg.encoding !== "uadp") errs.push("encoding=" + msg.encoding);
if (msg.transport !== "mqtt") errs.push("transport=" + msg.transport);
if (!msg.topic) errs.push("no topic");
node.warn(errs.length ? "[VALIDATE] T2 mqtt-uadp: FAIL - " + errs.join(", ")
                      : "[VALIDATE] T2 mqtt-uadp: PASS");
return msg;

const p = msg.payload || {};
const errs = [];
if (Math.abs(p.V - 99.5) > 1e-9) errs.push("V=" + p.V);
if (p.Name !== "json-t3") errs.push("Name=" + p.Name);
if (msg.encoding !== "json") errs.push("encoding=" + msg.encoding);
if (msg.transport !== "mqtt") errs.push("transport=" + msg.transport);
if (msg.writerGroupId !== 33) errs.push("wgId(CR-02)=" + msg.writerGroupId);
if (typeof msg.publisherId !== "number") errs.push("pidType(HI-02)=" + typeof msg.publisherId);
if (msg.publisherId !== 305419896) errs.push("pid=" + msg.publisherId);
const t = new Date(msg.timestamp).getTime();
if (isNaN(t)) errs.push("ts not a date");
else if (Math.abs(Date.now() - t) > 30000) errs.push("ts(HI-01) too far from now: " + msg.timestamp);
node.warn(errs.length ? "[VALIDATE] T3 mqtt-json: FAIL - " + errs.join(", ")
                      : "[VALIDATE] T3 mqtt-json: PASS");
return msg;

const p = msg.payload || {};
const errs = [];
if (msg.dataSetWriterId !== 1) errs.push("dswId=" + msg.dataSetWriterId);
if (p.A !== 111) errs.push("A=" + p.A);
if ("B" in p) errs.push("leaked B");
node.warn(errs.length ? "[VALIDATE] T4a multi-writer-dsw1: FAIL - " + errs.join(", ")
                      : "[VALIDATE] T4a multi-writer-dsw1: PASS");
return msg;

const p = msg.payload || {};
const errs = [];
if (msg.dataSetWriterId !== 2) errs.push("dswId=" + msg.dataSetWriterId);
if (p.B !== "writer-two") errs.push("B=" + p.B);
if ("A" in p) errs.push("leaked A");
node.warn(errs.length ? "[VALIDATE] T4b multi-writer-dsw2: FAIL - " + errs.join(", ")
                      : "[VALIDATE] T4b multi-writer-dsw2: PASS");
return msg;

flow.set("t5_key", false);
flow.set("t5_keep", false);
const v = (Date.now() & 0x7fffffff);
flow.set("t5_expect", v);
msg.payload = { Val: v };
return msg;

const p = msg.payload || {};
const empty = Object.keys(p).length === 0;
if (empty) flow.set("t5_keep", true);
else if (p.Val === flow.get("t5_expect")) flow.set("t5_key", true);
return null;

const key = flow.get("t5_key");
const keep = flow.get("t5_keep");
const errs = [];
if (!key) errs.push("no keyframe");
if (!keep) errs.push("no keepalive");
node.warn(errs.length ? "[VALIDATE] T5 cyclic-keepalive: FAIL - " + errs.join(", ")
                      : "[VALIDATE] T5 cyclic-keepalive: PASS");
return msg;

const p = msg.payload || {};
const errs = [];
const big = p.Big || "";
if (big.length !== 2000) errs.push("len=" + big.length);
if (big !== "X".repeat(2000)) errs.push("content mismatch");
if (p.Marker !== "end-2000") errs.push("Marker=" + p.Marker);
node.warn(errs.length ? "[VALIDATE] T6 chunking: FAIL - " + errs.join(", ")
                      : "[VALIDATE] T6 chunking: PASS");
return msg;

const errs = [];
if (typeof msg.publisherId !== "number") errs.push("type=" + typeof msg.publisherId);
if (msg.publisherId !== 305419896) errs.push("pid=" + msg.publisherId);
node.warn(errs.length ? "[VALIDATE] T7 publisherid-uint32: FAIL - " + errs.join(", ")
                      : "[VALIDATE] T7 publisherid-uint32: PASS");
return msg;

flow.set("t8_a", false);
flow.set("t8_b", false);
return null;

const a = flow.get("t8_a");
const b = flow.get("t8_b");
const errs = [];
if (!a) errs.push("subA(match) received nothing");
if (b) errs.push("subB(non-match) unexpectedly received");
node.warn(errs.length ? "[VALIDATE] T8 filtering: FAIL - " + errs.join(", ")
                      : "[VALIDATE] T8 filtering: PASS");
return msg;

const recv = flow.get("t9_recv");
node.warn(recv ? "[VALIDATE] T9 configversion-mismatch: FAIL - unexpectedly received DataSet msg"
               : "[VALIDATE] T9 configversion-mismatch: PASS (msg suppressed, error logged)");
return msg;
